export function pick(obj, keys) {
    const result = {};
    for (const key of keys) {
        if (key in obj)
            result[key] = obj[key];
    }
    return result;
}
export function omit(obj, keys) {
    const result = { ...obj };
    for (const key of keys) {
        delete result[key];
    }
    return result;
}
export function is_empty(obj) {
    return Object.keys(obj).length === 0;
}
export function sort(obj) {
    if (obj === null ||
        obj === undefined ||
        obj instanceof Map ||
        obj instanceof Set ||
        obj instanceof Date ||
        Array.isArray(obj) ||
        typeof obj !== 'object') {
        return obj;
    }
    else {
        return Object.keys(obj)
            .sort()
            .filter(key => obj[key] !== undefined)
            .reduce((sorted, key) => {
            sorted[key] = obj[key];
            return sorted;
        }, {});
    }
}
